        :param filter_loc: 用于筛选的查询语法
        :param timeout: 查找节点的超时时间
        :return: 兄弟元素或节点文本组成的列表
        """
        return self._get_brothers(filter_loc=filter_loc, direction='following', timeout=timeout)

